challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The UPF is the source of a data plane failure, causing severe packet loss for RTP media streams and blocking all UE-to-network SIP signaling.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "Check UPF's GTP-U packet rates on the N3 interface over a 120s window.",
          "expected_if_hypothesis_holds": "The values for `upf.gtp_indatapktn3upf_per_ue` and `upf.gtp_outdatapktn3upf_per_ue` are near zero or significantly below baseline.",
          "falsifying_observation": "The values for `upf.gtp_indatapktn3upf_per_ue` and `upf.gtp_outdatapktn3upf_per_ue` are within their typical range, indicating traffic is flowing correctly over the N3 interface.",
          "conflates_with": []
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='rtpengine', to_ip='<upf_n6_ip>'. Measures connectivity on the user plane path from RTPEngine to UPF.",
          "expected_if_hypothesis_holds": "High RTT or packet loss is observed.",
          "falsifying_observation": "Normal RTT and zero packet loss are observed.",
          "conflates_with": [
            "The rtpengine container's networking stack",
            "The network path between rtpengine and the UPF's N6 interface"
          ]
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='smf', to_ip='<upf_n4_ip>'. This is a partner probe to measure connectivity on the control plane path from SMF to UPF.",
          "expected_if_hypothesis_holds": "High RTT or packet loss is also observed on this path, suggesting the issue is with the UPF node itself.",
          "falsifying_observation": "Normal RTT and zero packet loss are observed. This result, combined with a failure in the rtpengine->upf probe, would suggest the fault lies on the N6 path or with RTPEngine, not the UPF itself.",
          "conflates_with": []
        }
      ],
      "notes": "This plan uses a compositional probe (`measure_rtt` from rtpengine) and a partner probe (from smf) to distinguish between a general UPF failure and a path-specific issue, addressing linter feedback A1. Probes also check data plane counters directly at the UPF."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The RTPEngine is the source of the media-plane packet loss, originating from its own networking stack or egress path, causing the observed quality collapse.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "Check for internal processing errors in RTPEngine over a 120s window.",
          "expected_if_hypothesis_holds": "The `ims.rtpengine.errors_per_second` metric is greater than zero, indicating active errors inside the RTPEngine relay.",
          "falsifying_observation": "The `ims.rtpengine.errors_per_second` metric is zero, indicating the observed loss is not caused by RTPEngine's internal relay logic.",
          "conflates_with": []
        },
        {
          "tool": "get_network_status",
          "args_hint": "Check the container status of 'rtpengine'.",
          "expected_if_hypothesis_holds": "The 'rtpengine' container is in a 'running' state.",
          "falsifying_observation": "The 'rtpengine' container is in an 'exited' or other non-running state, which would indicate a container crash rather than a media quality issue in a running instance.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "Check UPF's N3 interface packet rates to help isolate the location of the packet loss.",
          "expected_if_hypothesis_holds": "The `upf.gtp_indatapktn3upf_per_ue` and `upf.gtp_outdatapktn3upf_per_ue` metrics show traffic flowing in both directions. This would imply the path through the UPF to the RAN is healthy, pointing towards a problem at RTPEngine.",
          "falsifying_observation": "The UPF N3 packet counters show a significant drop, halt, or directional asymmetry in traffic. This would suggest the problem is located at the UPF or on the RAN, not at RTPEngine.",
          "conflates_with": []
        }
      ],
      "notes": "This plan attempts to isolate the fault to RTPEngine by checking for internal application-level errors and verifying that adjacent components in the data path (UPF) are still forwarding traffic as expected."
    }
  ]
}
